import React, { useEffect, useState } from "react";
import database from "./firebase";
import { ref, onValue } from "firebase/database";

function App() {
  const [leftFoot, setLeftFoot] = useState(null);
  const [rightFoot, setRightFoot] = useState(null);

  useEffect(() => {
    const leftRef = ref(database, "leftFoot");
    const rightRef = ref(database, "rightFoot");

    const unsubscribeLeft = onValue(leftRef, (snapshot) => {
      const data = snapshot.val();
      if (data) {
        const entries = Object.values(data);
        const latest = entries[entries.length - 1];
        setLeftFoot(latest);
      } else {
        setLeftFoot(null);
      }
    });

    const unsubscribeRight = onValue(rightRef, (snapshot) => {
      const data = snapshot.val();
      if (data) {
        const entries = Object.values(data);
        const latest = entries[entries.length - 1];
        setRightFoot(latest);
      } else {
        setRightFoot(null);
      }
    });

    return () => {
      unsubscribeLeft();
      unsubscribeRight();
    };
  }, []);

  const renderRow = (label, leftValue, rightValue) => (
    <tr className="even:bg-gray-50 hover:bg-blue-50 transition-colors duration-200 border-b border-gray-200">
      <td className="py-4 px-6 font-medium text-gray-800">{label}</td>
      <td className="py-4 px-6 text-gray-600">{leftValue ?? "—"}</td>
      <td className="py-4 px-6 text-gray-600">{rightValue ?? "—"}</td>
    </tr>
  );

  return (
    <div className="min-h-screen bg-gradient-to-br from-gray-100 to-blue-50 flex items-center justify-center p-4 sm:p-6">
      <div className="w-full max-w-6xl">
        <h1 className="text-3xl sm:text-4xl font-extrabold mb-8 text-center text-gray-900 tracking-tight">
          Latest Foot Sensor Data
        </h1>

        <div className="overflow-x-auto bg-white shadow-xl rounded-xl border border-gray-200">
          <table className="min-w-full table-auto border-collapse">
            <thead>
              <tr className="bg-gradient-to-r from-blue-600 to-blue-700 text-white text-left text-sm sm:text-base">
                <th className="py-4 px-6 font-semibold rounded-tl-xl">Data</th>
                <th className="py-4 px-6 font-semibold">Left Foot</th>
                <th className="py-4 px-6 font-semibold rounded-tr-xl">Right Foot</th>
              </tr>
            </thead>
            <tbody className="text-gray-700 text-sm sm:text-base">
              {renderRow("Timestamp", leftFoot?.timestamp, rightFoot?.timestamp)}
              {renderRow("Force (N)", leftFoot?.force, rightFoot?.force)}

              <tr className="bg-gray-100">
                <td className="py-3 px-6 font-semibold text-gray-800" colSpan="3">
                  Accelerometer
                </td>
              </tr>
              {renderRow("Accel X", leftFoot?.accel?.x, rightFoot?.accel?.x)}
              {renderRow("Accel Y", leftFoot?.accel?.y, rightFoot?.accel?.y)}
              {renderRow("Accel Z", leftFoot?.accel?.z, rightFoot?.accel?.z)}

              <tr className="bg-gray-100">
                <td className="py-3 px-6 font-semibold text-gray-800" colSpan="3">
                  Gyroscope
                </td>
              </tr>
              {renderRow("Gyro X", leftFoot?.gyro?.x, rightFoot?.gyro?.x)}
              {renderRow("Gyro Y", leftFoot?.gyro?.y, rightFoot?.gyro?.y)}
              {renderRow("Gyro Z", leftFoot?.gyro?.z, rightFoot?.gyro?.z)}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
}

export default App;
